5. `LoopDriver.runSession` + termination ŌĆö `lib/src/loop_driver/loop_driver.dart` (extend)

   Constants: `maxTurns = 50`, `sessionBudget = Duration(minutes: 15)`, `maxConsecutiveFailedTurns = 3`. `_clock` injected (default `() => DateTime.now()`) so the 15-min test can advance time.

   ```dart
   Future<SessionTermination> runSession() async {
     _sessionStart = _clock();
     try {
       while (true) {
         if (_turnIndex >= maxTurns ||
             _clock().difference(_sessionStart) >= sessionBudget) {
           return _terminate(SessionOutcome.budgetExhausted);
         }
         if (_consecutiveFailedTurns >= maxConsecutiveFailedTurns) {
           return _terminate(SessionOutcome.harnessError,
               harnessError: HarnessError.agentStuck);
         }
         try {
           await runTurn();
           if (_doneRequested) {
             return _terminate(SessionOutcome.done, finalSummary: _doneReason);
           }
         } on TurnFailure { /* counted by runTurn; loop continues */ }
         on VmServiceConnectionLost {
           return _terminate(SessionOutcome.harnessError,
               harnessError: HarnessError.connectionLost);
         }
       }
     } finally { await writer.close(); }
   }
   Future<SessionTermination> _terminate(SessionOutcome o,
       {HarnessError? harnessError, String? finalSummary}) async {
     await writer.writeFooter(SessionFooter(
       outcome: o.name, finalSummary: finalSummary ?? summary.text,
       totalTurns: _turnIndex,
       totalDurationMs: _clock().difference(_sessionStart).inMilliseconds,
       harnessError: harnessError?.name));
     return SessionTermination(o, harnessError: harnessError, finalSummary: finalSummary);
   }
   ```

