3. **`ActionValidator.validate`** ŌĆö `packages/exploration_agent/lib/src/validation/action_validator.dart` (new file)

   Three passes in order. First match wins.

   ```dart
   class ActionValidator {
     const ActionValidator();

     ValidationResult validate(
       ValidatorAction action,
       Observation observation,
       List<ToolDescriptor> tools,
     ) {
       // Pass 1: tool known?
       final ToolDescriptor? tool =
           tools.firstWhereOrNull((t) => t.name == action.tool);
       if (tool == null) {
         return ValidationReject(
           tool: action.tool,
           reason: 'unknown_tool',
           expected: tools.map((t) => t.name).toList(growable: false),
           got: action.tool,
           description: 'tool "${action.tool}" is not available this turn',
         );
       }

       // Pass 2: args validate against inputSchema?
       final schema = JsonSchema.create(tool.inputSchema);
       final result = schema.validate(action.args);
       if (!result.isValid) {
         final err = result.errors.first;
         return ValidationReject(
           tool: action.tool,
           reason: 'schema_invalid',
           pointer: err.instancePath,
           description: err.message,
         );
       }

       // Pass 3: core-tool semantic-node check (only for core.* tools that
       // take node_id / scrollable_id / target_id).
       const coreNodeTools = <String>{
         'core.tap', 'core.long_press', 'core.enter_text',
         'core.scroll_until_visible', 'core.inspect_widget', 'core.scroll',
         'core.gesture',
       };
       if (!coreNodeTools.contains(action.tool)) {
         return const ValidationOk();  // plugin-namespaced or wait/done/system_back: skip node pass
       }

       // Collect node id args present in this action.
       final ids = <(String, int)>[];
       for (final key in const ['node_id', 'scrollable_id', 'target_id']) {
         final v = action.args[key];
         if (v is int) ids.add((key, v));
       }
       for (final (argKey, id) in ids) {
         final node = observation.core.nodes[id];
         if (node == null) {
           return ValidationReject(
             tool: action.tool,
             reason: 'node_not_found',
             pointer: '/$argKey',
             got: id,
             description: '$argKey=$id is not present in observation.core.nodes',
           );
         }
         if (node.state.contains('disabled')) {
           return ValidationReject(
             tool: action.tool,
             reason: 'node_disabled',
             pointer: '/$argKey',
             got: id,
             description: '$argKey=$id is disabled (state: ${node.state})',
           );
         }
       }
       return const ValidationOk();
     }
   }
   ```

