   ```dart
   ({String json, int bytes, bool truncated}) encodeWithBudget(Map<String,dynamic> frag, int budget) {
     final raw = jsonEncode(frag); final bytes = utf8.encode(raw).length;
     if (bytes <= budget) return (json: raw, bytes: bytes, truncated: false);
     final marker = jsonEncode({'_truncated': true, 'originalBytes': bytes, 'budgetBytes': budget});
     return (json: marker, bytes: utf8.encode(marker).length, truncated: true);
   }
   Map<String,int> distributePluginBudgets(Map<String,int> req, List<String> namespaces,
       {int defaultPer = 1024, int totalCap = 2048}) {
     final eff = { for (final n in namespaces) n: req[n] ?? defaultPer };
     final sum = eff.values.fold<int>(0, (a,b) => a+b);
     if (sum <= totalCap) return eff;
     final scale = totalCap / sum;
     return eff.map((k,v) => MapEntry(k, (v * scale).floor()));
   }
   ```
