2. Add `_Rec`, walk, obscured filter, and role/state/action mapping ŌĆö same file `packages/exploration_flutter/lib/src/semantics/semantics_capture.dart`

   ```dart
   class _Rec {
     _Rec(this.id, this.role, this.label, this.state, this.actions, this.rect);
     final int id;
     final String role, label;
     final List<String> state, actions;
     final Rect rect;
     bool dropped = false;
     Map<String, Object> toJson() {
       final m = <String, Object>{
         'id': id, 'role': role,
         'rect': <int>[rect.left.round(), rect.top.round(),
             rect.right.round(), rect.bottom.round()],
       };
       if (label.isNotEmpty) m['label'] = label;
       if (state.isNotEmpty) m['state'] = state;
       if (actions.isNotEmpty) m['actions'] = actions;
       return m;
     }
   }

   const Map<int, String> _roleFlags = <int, String>{
     // SemanticsFlag.<X>.index -> role string
   };

   extension on SemanticsCapture {
     void _walk(SemanticsNode n, List<_Rec> out, Rect viewport) {
       final SemanticsData d = n.getSemanticsData();
       if (d.hasFlag(SemanticsFlag.isHidden)) return;
       final Rect r = MatrixUtils.transformRect(
           n.transform ?? Matrix4.identity(), n.rect);
       if (!r.overlaps(viewport)) return;
       out.add(_Rec(_stableIdFor(n), _role(d), d.label,
           _state(d), _actions(d), r));
       n.visitChildren((c) { _walk(c, out, viewport); return true; });
     }

     void _filterObscured(List<_Rec> ns) {
       for (int i = 0; i < ns.length; i++) {
         final Rect a = ns[i].rect;
         for (int j = i + 1; j < ns.length; j++) {
           if (ns[j].dropped) continue;
           final Rect b = ns[j].rect;
           if (b.left <= a.left && b.top <= a.top &&
               b.right >= a.right && b.bottom >= a.bottom && b != a) {
             ns[i].dropped = true; break;
           }
         }
       }
     }

     String _role(SemanticsData d) {
       if (d.hasFlag(SemanticsFlag.isButton)) return 'button';
       if (d.hasFlag(SemanticsFlag.isTextField)) return 'textfield';
       if (d.hasFlag(SemanticsFlag.isLink)) return 'link';
       if (d.hasFlag(SemanticsFlag.isHeader)) return 'header';
       if (d.hasFlag(SemanticsFlag.isImage)) return 'image';
       if (d.hasFlag(SemanticsFlag.hasCheckedState)) return 'checkbox';
       if (d.hasFlag(SemanticsFlag.hasToggledState)) return 'switch';
       if (d.hasFlag(SemanticsFlag.isSlider)) return 'slider';
       return 'text';
     }

     List<String> _state(SemanticsData d) {
       final f = <String>[];
       if (d.hasFlag(SemanticsFlag.isChecked)) f.add('checked');
       if (d.hasFlag(SemanticsFlag.isToggled)) f.add('on');
       if (d.hasFlag(SemanticsFlag.isSelected)) f.add('selected');
       if (d.hasFlag(SemanticsFlag.isFocused)) f.add('focused');
       if (d.hasFlag(SemanticsFlag.hasEnabledState) &&
           !d.hasFlag(SemanticsFlag.isEnabled)) f.add('disabled');
       if (d.hasFlag(SemanticsFlag.isObscured)) f.add('obscured');
       return f;
     }

     List<String> _actions(SemanticsData d) {
       const t = <SemanticsAction, String>{
         SemanticsAction.tap: 'tap',
         SemanticsAction.longPress: 'long_press',
         SemanticsAction.scrollLeft: 'scroll_left',
         SemanticsAction.scrollRight: 'scroll_right',
         SemanticsAction.scrollUp: 'scroll_up',
         SemanticsAction.scrollDown: 'scroll_down',
         SemanticsAction.increase: 'increase',
         SemanticsAction.decrease: 'decrease',
         SemanticsAction.setText: 'set_text',
       };
       final out = <String>[];
       t.forEach((k, v) {
         if ((d.actions & k.index) != 0) out.add(v);
       });
       return out;
     }
   }
   ```

