4. Provider class ŌĆö `packages/exploration_agent/lib/src/provider/openai/openai_provider.dart`

   ```dart
   import 'dart:async'; import 'dart:convert';
   import 'package:http/http.dart' as http;
   import '../types.dart'; import '../action_schema.dart';
   import '../model_provider.dart';
   import '../frontier/frontier_defaults.dart';
   import 'openai_models.dart';
   import 'openai_request.dart';
   import 'openai_parse.dart';

   class OpenAiModelProvider implements ModelProvider {
     final String modelId, apiKey;
     final Uri endpoint;
     final http.Client _client;
     final FrontierDefaults _defaults;
     final _thinking = StreamController<ThinkingDelta>.broadcast();

     OpenAiModelProvider({required this.modelId, required this.apiKey,
       Uri? endpoint, http.Client? client, FrontierDefaults? defaults})
       : endpoint = endpoint ?? Uri.parse('https://api.openai.com/v1/chat/completions'),
         _client = client ?? http.Client(),
         _defaults = defaults ?? FrontierDefaults.openai();

     @override
     ModelCapabilities get capabilities {
       final m = openAiModels[modelId];
       if (m == null) throw ArgumentError('unknown model: $modelId');
       return m.capabilities;
     }
     @override
     Stream<ThinkingDelta> thinking() => _thinking.stream;

     @override
     Future<ModelDecision> decide(PromptPayload p, ActionSchema s) async {
       try { return await _attempt(p, s, null); }
       on SchemaRejection catch (e) { return await _attempt(p, s, e.validationError); }
     }

     Future<ModelDecision> _attempt(PromptPayload p, ActionSchema s, String? note) async {
       final body = buildOpenAiRequest(model: modelId, prompt: p, schema: s,
         defaults: _defaults, schemaErrorNote: note);
       final res = await _client.post(endpoint, headers: {
         'Content-Type': 'application/json', 'Authorization': 'Bearer $apiKey',
       }, body: jsonEncode(body));
       if (res.statusCode >= 400) {
         throw StateError('openai http ${res.statusCode}: ${res.body}');
       }
       return parseOpenAiResponse(jsonDecode(res.body) as Map<String, dynamic>,
         schema: s, tools: p.tools);
     }

     Future<void> streamThinking(PromptPayload prompt, ActionSchema schema) async {
       final body = buildOpenAiRequest(model: modelId, prompt: prompt,
         schema: schema, defaults: _defaults, stream: true);
       final req = http.Request('POST', endpoint)
         ..headers['Content-Type'] = 'application/json'
         ..headers['Authorization'] = 'Bearer $apiKey'
         ..body = jsonEncode(body);
       final res = await _client.send(req);
       await for (final line in res.stream
           .transform(utf8.decoder).transform(const LineSplitter())) {
         if (!line.startsWith('data: ')) continue;
         final p = line.substring(6).trim();
         if (p == '[DONE]') {
           _thinking.add(const ThinkingDelta(text: '', isFinal: true));
           return;
         }
         final m = jsonDecode(p) as Map<String, dynamic>;
         final d = ((m['choices'] as List).first as Map)['delta'] as Map?;
         final t = d?['content'] as String?;
         if (t != null && t.isNotEmpty) {
           _thinking.add(ThinkingDelta(text: t, isFinal: false));
         }
       }
     }

     Future<void> close() async { await _thinking.close(); _client.close(); }
   }
   ```

