              '(${_args(record.executedAction.args)})',
              maxLines: 1, overflow: TextOverflow.ellipsis),
         Text(_diff(record.diff), maxLines: 1, overflow: TextOverflow.ellipsis),
         Text(record.summaryUpdate ?? '', maxLines: 1,
              overflow: TextOverflow.ellipsis),
       ])));
     static String _args(Map<String, dynamic> a) =>
       a.entries.take(3).map((e) => '${e.key}=${e.value}').join(', ');
     static String _diff(ObservationDiff d) {
       final p = <String>[];
       if (d.core.nodesAdded.isNotEmpty) p.add('+${d.core.nodesAdded.length} nodes');
       if (d.core.nodesRemoved.isNotEmpty) p.add('-${d.core.nodesRemoved.length} nodes');
       if (d.core.routeChanges.isNotEmpty)
         p.add('route -> ${d.core.routeChanges.last.current.join("/")}');
       for (final e in d.plugins.entries) p.add('${e.key}: ${e.value.runtimeType}');
       return p.isEmpty ? '(no changes)' : p.join(', ');
     }
   }
