   ```dart
   import 'dart:convert';
   import 'package:dtd/dtd.dart';
   import 'package:exploration_agent/exploration_agent.dart';

   class DtdTrajectorySink implements TrajectorySink {
     DtdTrajectorySink(this._dtd, this._uri);
     final DartToolingDaemon _dtd;
     final Uri _uri;
     bool _closed = false;

     @override
     Future<void> writeLine(String jsonLine) async {
       if (_closed) throw StateError('sink closed');
       String prev;
       try {
         prev = (await _dtd.readFileAsString(_uri, encoding: utf8)).content;
       } on DtdException { prev = ''; }
       await _dtd.writeFileAsString(_uri, '$prev$jsonLine\n', encoding: utf8);
     }

     @override Future<void> close() async { _closed = true; }
   }
   ```

   Per-call full-write keeps .19's per-turn-flush invariant; DTD has no append primitive, so read-then-write is the correct shape.

