2. **`RunningSummary` with hard + soft caps** ŌĆö `packages/exploration_agent/lib/src/memory/running_summary.dart` (new file)

   ```dart
   class SummaryOversizeError extends Error {
     SummaryOversizeError({required this.tokenCount, required this.cap});
     final int tokenCount;
     final int cap;
     @override
     String toString() =>
         'SummaryOversizeError: $tokenCount tokens > cap=$cap';
   }

   class RunningSummary {
     RunningSummary({
       required TokenCounter counter,
       this.softCap = 500,
       this.hardCap = 1000,
     }) : _counter = counter;

     final TokenCounter _counter;
     final int softCap;
     final int hardCap;
     String _text = '';
     bool _softCapExceeded = false;

     String get text => _text;
     bool get softCapExceeded => _softCapExceeded;

     /// Replace the running summary with [text]. Throws [SummaryOversizeError]
     /// when the token count exceeds [hardCap]. Sets [softCapExceeded] when
     /// the count exceeds [softCap] (but is still <= [hardCap]).
     void update(String text) {
       final n = _counter.count(text);
       if (n > hardCap) {
         throw SummaryOversizeError(tokenCount: n, cap: hardCap);
       }
       _text = text;
       _softCapExceeded = n > softCap;
     }
   }
   ```

