2. Auditor walker ŌĆö `exploration_flutter/lib/src/diagnostics/interactive_semantics_auditor.dart`

   ```dart
   import 'package:flutter/material.dart';
   import 'package:flutter/widgets.dart';
   import 'interactive_semantics_warning.dart';

   class InteractiveSemanticsAuditor {
     InteractiveSemanticsAuditor({this.extraInteractiveTypes = const []});
     final List<String> extraInteractiveTypes;

     List<InteractiveSemanticsWarning> audit(Element root) {
       final out = <InteractiveSemanticsWarning>[];
       void visit(Element el) {
         final w = el.widget;
         final type = w.runtimeType.toString();
         if (_isInteractive(w, type) && !_hasAncestorSemantics(el)) {
           out.add(InteractiveSemanticsWarning(
             widgetType: type,
             location: _locationOf(el),
             suggestedFixPointer: kPluginGuideFixPointer,
           ));
         }
         el.visitChildren(visit);
       }
       root.visitChildren(visit);
       return out;
     }

     bool _isInteractive(Widget w, String type) {
       if (w is GestureDetector) {
         return w.onTap != null || w.onLongPress != null || w.onDoubleTap != null;
       }
       if (w is InkResponse) {
         return w.onTap != null || w.onLongPress != null || w.onDoubleTap != null;
       }
       return extraInteractiveTypes.contains(type);
     }

     bool _hasAncestorSemantics(Element el) {
       var found = false;
       el.visitAncestorElements((a) {
         if (a.widget is Semantics) {
           final s = a.widget as Semantics;
           if (s.properties.label != null || s.properties.button == true) {
             found = true;
             return false;
           }
         }
         return true;
       });
       return found;
     }

     String _locationOf(Element el) {
       try { return el.debugGetCreatorChain(1); }
       catch (_) { return el.widget.runtimeType.toString(); }
     }
   }
   ```

